import std/[tables, strutils]
proc wordCount(text: string): Table[string, int] =
  result = initTable[string, int]()
  for word in text.split():
    let w = word.toLowerAscii()
    if result.hasKey(w):
      result[w] += 1
    else:
      result[w] = 1
echo wordCount("a a b c")

import std/deques
proc rotate[T](items: seq[T], n: int): seq[T] =
  var d: Deque[T] = initDeque[T]()
  for item in items: d.addLast(item)
  for _ in 0..<n:
    d.addLast(d.popFirst())
  result = @[]
  while d.len > 0:
    result.add(d.popFirst())
echo rotate(@[1, 2, 3, 4, 5], 2)

