import std/strutils
proc columnSums(text: string): seq[int] =
  for line in text.strip().splitLines():
    let vals = line.split("|")
    if result.len == 0:
      result.setLen(vals.len)
      continue
    for i, v in vals:
      result[i] += parseInt(v.strip())
echo columnSums("a|b\n1|2\n3|4")

