import std/net

proc isPortOpen(host: string, port: Port): bool =
  try:
    let sock = newSocket()
    sock.connect(host, port, 2000)
    sock.close()
    return true
  except:
    return false

echo isPortOpen("127.0.0.1", Port(9999))

import std/httpclient, std/strutils
proc fetchStatus(url: string): int =
  try:
    let client = newHttpClient(timeout = 3000)
    try:
      let resp = client.get(url)
      return parseInt(resp.status)
    finally:
      client.close()
  except:
    return 0
echo fetchStatus("http://example.com/")

